-- TRILHA: MOBILE DEVELOPMENT
SET @mobile_id = (SELECT id FROM courses WHERE title = 'Mobile Development' LIMIT 1);

INSERT INTO modules (course_id, title) VALUES (@mobile_id, 'Fundamentos Mobile');
SET @mobile_mod1 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, exercises) VALUES
(@mobile_mod1, 'Diferenças Web vs Mobile', '<h2>Diferenças Web vs Mobile</h2><p>O desenvolvimento mobile possui características únicas que o diferenciam do web:</p><h3>Características Mobile</h3><ul><li><strong>Tela Pequena:</strong> Interfaces devem ser otimizadas para telas menores</li><li><strong>Touch Interactions:</strong> Gestos táteis ao invés de mouse/teclado</li><li><strong>Offline First:</strong> Aplicações devem funcionar sem internet</li><li><strong>Performance:</strong> Menos recursos disponíveis que em desktops</li><li><strong>Bateria:</strong> Otimização de consumo é crítica</li></ul>', '[{"id": 1, "title": "Qual é a altura mínima para um botão em mobile?", "type": "multiple_choice", "options": ["24px", "48px", "72px", "100px"], "correct": 1}]'),
(@mobile_mod1, 'Escolhendo o Framework Certo', '<h2>Escolhendo o Framework Certo</h2><h3>React Native</h3><p><strong>Vantagens:</strong> Usa JavaScript/React, comunidade grande, muitas bibliotecas, hot reload</p><h3>Flutter</h3><p><strong>Vantagens:</strong> Performance excepcional, UI consistente, Material Design built-in</p>', '[{"id": 1, "title": "Qual framework oferece melhor performance?", "type": "multiple_choice", "options": ["React Native", "Flutter", "Xamarin", "Ionic"], "correct": 1}]'),
(@mobile_mod1, 'Setup do Ambiente de Desenvolvimento', '<h2>Setup do Ambiente</h2><h3>Para React Native</h3><pre><code>npm install -g react-native-cli\nnpx react-native init MyApp</code></pre><h3>Para Flutter</h3><pre><code>flutter create my_app\nflutter run</code></pre>', '[{"id": 1, "title": "Qual comando verifica dependências no Flutter?", "type": "multiple_choice", "options": ["flutter check", "flutter doctor", "flutter verify", "flutter setup"], "correct": 1}]');

INSERT INTO modules (course_id, title) VALUES (@mobile_id, 'React Native');
SET @mobile_mod2 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, exercises) VALUES
(@mobile_mod2, 'React Native Básico', '<h2>React Native Básico</h2><h3>Componentes Principais</h3><p><strong>View:</strong> Container básico</p><p><strong>Text:</strong> Para exibir texto</p><p><strong>ScrollView:</strong> Para conteúdo rolável</p><p><strong>FlatList:</strong> Para listas otimizadas</p>', '[{"id": 1, "title": "Qual componente é usado para exibir texto?", "type": "multiple_choice", "options": ["View", "Text", "Paragraph", "Label"], "correct": 1}]'),
(@mobile_mod2, 'Navegação em React Native', '<h2>Navegação em React Native</h2><h3>React Navigation</h3><p>Biblioteca padrão para navegação em React Native</p><h3>Tipos de Navegação</h3><ul><li><strong>Stack:</strong> Pilha de telas</li><li><strong>Tab:</strong> Abas na parte inferior</li><li><strong>Drawer:</strong> Menu lateral</li></ul>', '[{"id": 1, "title": "Qual é o tipo de navegação mais comum?", "type": "multiple_choice", "options": ["Stack", "Drawer", "Tab", "Modal"], "correct": 0}]'),
(@mobile_mod2, 'Hooks e State Management', '<h2>Hooks em React Native</h2><h3>useState</h3><p>Hook para gerenciar estado local</p><h3>useEffect</h3><p>Hook para efeitos colaterais</p><h3>Context API</h3><p>Para compartilhar estado globalmente</p>', '[{"id": 1, "title": "Qual hook é para efeitos colaterais?", "type": "multiple_choice", "options": ["useState", "useEffect", "useContext", "useReducer"], "correct": 1}]');

INSERT INTO modules (course_id, title) VALUES (@mobile_id, 'Flutter & Dart');
SET @mobile_mod3 = LAST_INSERT_ID();

INSERT INTO lessons (module_id, title, content, exercises) VALUES
(@mobile_mod3, 'Dart Fundamentos', '<h2>Dart Fundamentos</h2><h3>Tipos de Dados</h3><p>String, int, double, bool, List, Map</p><h3>Funções</h3><p>Funções com tipos de retorno, arrow functions, parâmetros nomeados</p>', '[{"id": 1, "title": "Qual é a sintaxe de arrow function em Dart?", "type": "multiple_choice", "options": ["=>", "->", "~>", "=>"], "correct": 0}]'),
(@mobile_mod3, 'Widgets e UI em Flutter', '<h2>Widgets em Flutter</h2><h3>Widgets Comuns</h3><ul><li><strong>Scaffold:</strong> Estrutura básica</li><li><strong>Container:</strong> Box com padding/margin</li><li><strong>Row/Column:</strong> Layouts</li><li><strong>ListView:</strong> Lista rolável</li></ul>', '[{"id": 1, "title": "Qual widget é para layout vertical?", "type": "multiple_choice", "options": ["Row", "Column", "Stack", "Flex"], "correct": 1}]'),
(@mobile_mod3, 'State Management em Flutter', '<h2>State Management em Flutter</h2><h3>StatefulWidget</h3><p>Widget com estado mutável</p><h3>Provider Package</h3><p>Solução de state management escalável</p>', '[{"id": 1, "title": "Qual método atualiza UI em StatefulWidget?", "type": "multiple_choice", "options": ["update()", "refresh()", "setState()", "rebuild()"], "correct": 2}]');

SELECT COUNT(*) as total_mobile FROM lessons WHERE module_id IN (SELECT id FROM modules WHERE course_id = @mobile_id);

